void insertFront(Node*& head, int val) {
    Node* newNode = new Node(val);
    if (!head) {
        head = newNode;
        head->next = head;
        return;
    }
    Node* tail = head;
    while (tail->next != head) tail = tail->next;
    newNode->next = head;
    tail->next = newNode;
    head = newNode;
}

