    Node(int d) : data(d), next(nullptr) {}
};

void deleteNode(Node*& head, int val) {
    if (!head) return;
    Node* curr = head;
    Node* prev = nullptr;
    // Find node to delete
    do {
        if (curr->data == val) break;
        prev = curr;
        curr = curr->next;
    } while (curr != head);
    if (curr->data != val) return;
    if (curr == head && curr->next == head) { // only one node
        delete head;
        head = nullptr;
        return;
    }
    if (curr == head) { // delete head
        // find tail
        Node* tail = head;
        while (tail->next != head) tail = tail->next;
        head = head->next;
        tail->next = head;
        delete curr;
    } else {
        prev->next = curr->next;
        delete curr;
    }
}

