#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node(int d) : data(d), next(nullptr) {}
};

int josephus(int n, int k) {
    // Create circular list 1..n
    Node* head = new Node(1);
    Node* prev = head;
    for (int i = 2; i <= n; i++) {
        prev->next = new Node(i);
        prev = prev->next;
    }
    prev->next = head; // make circular
    // Eliminate
    Node* curr = head;
    Node* prevNode = prev;
    while (n > 1) {
        // move k-1 steps
        for (int i = 1; i < k; i++) {
            prevNode = curr;
            curr = curr->next;
        }
        // remove curr
        prevNode->next = curr->next;
        delete curr;
        curr = prevNode->next;
        n--;
    }
    int survivor = curr->data;
    delete curr;
    return survivor;
}

int main() {
    cout << josephus(7, 3) << endl; // 4
    return 0;
}

#include <iostream>
using namespace std;

struct DNode {
    int data;
    DNode* prev;
    DNode* next;
    DNode(int d) : data(d), prev(nullptr), next(nullptr) {}
};

class DoublyCircularList {
    DNode* head;
public:
    DoublyCircularList() : head(nullptr) {}
    void insertFront(int val) {
        DNode* newNode = new DNode(val);
        if (!head) {
            head = newNode;
            head->next = head;
            head->prev = head;
        } else {
            DNode* tail = head->prev;
            newNode->next = head;
            newNode->prev = tail;
            head->prev = newNode;
            tail->next = newNode;
            head = newNode;
        }
    }
    void printForward() {
        if (!head) return;
        DNode* curr = head;
        do {
            cout << curr->data << " ";
            curr = curr->next;
        } while (curr != head);
        cout << endl;
    }
    void printBackward() {
        if (!head) return;
        DNode* curr = head->prev; // start from tail
        do {
            cout << curr->data << " ";
            curr = curr->prev;
        } while (curr != head->prev);
        cout << endl;
    }
};

int main() {
    DoublyCircularList dcl;
    dcl.insertFront(30); dcl.insertFront(20); dcl.insertFront(10);
    dcl.printForward();   // 10 20 30
    dcl.printBackward();  // 30 20 10
    return 0;
}

