using namespace std;

// Round-robin scheduler simulation
struct Process {
    int pid;
    int burstTime;
    Process* next;
    Process(int id, int bt) : pid(id), burstTime(bt), next(nullptr) {}
};

void roundRobin(Process*& head, int timeQuantum) {
    if (!head) return;
    Process* curr = head;
    Process* prev = nullptr;
    while (true) {
        if (curr->burstTime > 0) {
            int exec = min(curr->burstTime, timeQuantum);
            cout << "Process " << curr->pid << " executes for " << exec << " units." << endl;
            curr->burstTime -= exec;
            if (curr->burstTime == 0) {
                // remove process
                if (curr == head) {
                    // find last
                    Process* last = head;
                    while (last->next != head) last = last->next;
                    if (head->next == head) { head = nullptr; delete curr; break; }
                    head = head->next;
                    last->next = head;
                    delete curr;
                    curr = head;
                    continue;
                } else {
                    prev->next = curr->next;
                    delete curr;
                    curr = prev->next;
                    continue;
                }
            }
        }
        prev = curr;
        curr = curr->next;
        if (curr == head) break; // one full round
    }
}

int main() {
    Process* head = new Process(1, 10);
    head->next = new Process(2, 5);
    head->next->next = new Process(3, 8);
    head->next->next->next = head;
    roundRobin(head, 3);
    return 0;
}
